{"output":"import { ControllerRenderProps, FieldValues, useController, useFormContext } from 'react-hook-form';

export type YupError = string | { message: string };

export const normalizeError = (yupError: YupError | undefined) => {
  if (yupError && typeof yupError === 'object') {
    return yupError.message;
  }
  return yupError;
};
interface IReturn {
  error: string | undefined;
  field: ControllerRenderProps<FieldValues, string>;
  invalid: boolean;
}

interface IProps {
  name: string;
}

export const useControl = ({ name }: IProps): IReturn => {
  const { control } = useFormContext();
  const {
    field,
    fieldState: { error, invalid },
  } = useController({ control, name });

  return { error: error?.message, field, invalid };
};
